# --------------------------------- MAIN ---------------------------------


def main():
    # sg.theme_previewer()
    # sg.theme('Dark gray 10')
    flashcards = load_flashcards('inversions.flash')
    G.number_of_cards = len(flashcards)
    # sg.popup_scrolled('\n'.join([f'{c.filename} - {c.answer}'for c in flashcards]), title='Flashcards')
    load_settings()
    # row_len = 6
    # num_images = 36
    # image_grid = [[sg.Image(flashcards[c + j * row_len].image) for c in range(0, row_len)] for j in range(0, num_images // row_len)]

    layout = [[sg.P(), sg.Image(settings_icon, subsample=15, enable_events=True, k='-SETTINGS-')],
              [sg.Image(source=back_icon, subsample=6, enable_events=True, k='-BACK-'), sg.Push(), sg.Image(flashcards[0].image, k='-IMAGE-'), sg.Push(), sg.Image(source=forward_icon, subsample=6, enable_events=True, k='-FORWARD-')],
              [],
              [sg.P(), sg.Button(size=(10,1), k='-ANSWER-', font='_ 18'), sg.P()],
              [sg.P(),sg.Button(image_source=play_icon, k='-PLAY-', image_subsample=8, border_width=0, button_color=(sg.theme_button_color_text(), sg.theme_background_color())),
                           sg.Button(image_source=pause_red_icon, k='-PAUSE-', image_subsample=8, border_width=0, button_color=(sg.theme_button_color_text(), sg.theme_background_color())), sg.P()]]
              # [sg.Push(), sg.Button(sg.SYMBOL_X_SMALL, button_color=(sg.theme_button_color_text(), sg.theme_background_color()), border_width=0, font='_18', k='Exit')]]


    window = sg.Window("Inversions Flashcards", layout, finalize=True, auto_save_location=True, keep_on_top=True, use_custom_titlebar=True)

    card_index = 0

    while True:
        event, values = window.read()
        # print(event, values)
        if event in (sg.WIN_CLOSED, "Exit"):
            break
        elif event == '-FORWARD-':
            if G.show_answer:
                window['-ANSWER-'].update(flashcards[card_index].answer)
                window.timer_start(f'00:00:{G.answer_delay_time}', repeating=False, key='-timer forward-')
            else:
                card_index = next_card(card_index)
                window['-ANSWER-'].update('')
                if not G.paused:
                    window.timer_start(f'00:00:{G.time_per_card}', repeating=False, key='-FORWARD-')
        elif event == '-timer forward-':
            card_index = next_card(card_index)
            if not G.paused:
                window.timer_start(f'00:00:{G.time_per_card}', repeating=False, key='-FORWARD-')
            window['-ANSWER-'].update('')
        elif event == '-BACK-':
            card_index = prev_card(card_index)
            window['-ANSWER-'].update('')
        elif event == '-ANSWER-':
            window['-ANSWER-'].update(flashcards[card_index].answer)
        elif event == '-SETTINGS-':
            show_settings_window(location=window.current_location())
            load_settings()
        elif event == '-PLAY-':
            window['-PLAY-'].update(image_source=play_red_icon,  image_subsample=8)
            window['-PAUSE-'].update(image_source=pause_icon,  image_subsample=8)
            G.paused = False
            window.timer_stop_all()
            window.timer_start(f'00:00:{G.time_per_card}', repeating=False, key='-FORWARD-')
        elif event == '-PAUSE-':
            window['-PLAY-'].update(image_source=play_icon, image_subsample=8)
            window['-PAUSE-'].update(image_source=pause_red_icon, image_subsample=8)
            G.paused = True
            window.timer_stop_all()

        window['-IMAGE-'].update(flashcards[card_index].image)

    window.close()


play_red_icon = b''

pause_red_icon = b''

play_icon = b''

pause_icon = b''


back_icon = b''

forward_icon = b''

settings_icon = b''

if __name__ == '__main__':
    main()
